import{_ as a,o as t,c as s,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"58B. Special Disaster Leave","description":"","frontmatter":{"title":"58B. Special Disaster Leave","eba":"Medical Specialists 2022-2026","topics":["leave","personal-leave","employment"]},"headers":[],"relativePath":"ebas/medical-specialists/leave/58B-special-disaster-leave.md","filePath":"ebas/medical-specialists/leave/58B-special-disaster-leave.md"}'),o={name:"ebas/medical-specialists/leave/58B-special-disaster-leave.md"};function i(l,e,n,c,p,d){return t(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="_58b-special-disaster-leave" tabindex="-1">58B. Special Disaster Leave <a class="header-anchor" href="#_58b-special-disaster-leave" aria-label="Permalink to &quot;58B. Special Disaster Leave&quot;">​</a></h1><p><strong>58B.1</strong> Special disaster leave of up to 3 days per calendar year is payable where:</p><p><strong>(c)</strong> the Doctor is a full time or Fractional Doctor;</p><p><strong>(d)</strong> Personal Leave is not available either because the Doctor has exhausted the accrual or the circumstance does not qualify for Personal Leave; and</p><p><strong>(e)</strong> the Doctor is unable to attend work due to a disaster (such as fire or flood) where:</p><p><strong>(i)</strong> the Doctor&#39;s residence is damaged or under imminent threat of major damage;</p><p><strong>(ii)</strong> the lives or safety of their immediate family or household members are threatened; or</p><p><strong>(iii)</strong> there is a formal closure, flooding or other unusual danger of the use of a road(s) which is the Doctor&#39;s normal travel route to work and no alternative practicable travel route is available.</p><p><strong>58B.2</strong> Special disaster leave is non-cumulative.</p><p>Plain language terms: disaster leave, flood, bushfire.</p>',10)])])}const u=a(o,[["render",i]]);export{m as __pageData,u as default};
